import styled from "styled-components";

import backgroundImage from '../../img/ContactForm/bg.jpg'

const ContactForm = ({ id }) => {
  return (
    <ContactFormContainer id={id}>
      <h3> Do you want to ask me a question? </h3>
      <h4> Use a contact form listed below </h4>
      <Form>
        <InputGroup>
          Name: <input type="text" />        
        </InputGroup>
        <InputGroup>
          Email: <input type="email" />
        </InputGroup>
        <InputGroup>
          Message: <textarea />
        </InputGroup>
        <SubmitButton> Send </SubmitButton>
      </Form>
    </ContactFormContainer>
  )
}

const ContactFormContainer = styled.section`
  padding: 10em 0;
  background-size: cover;

  color: white;

  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  row-gap: 1em;
  box-shadow: 0px 0px 2px black;

  position: relative;
  &:before {
    content: "";
    position: absolute;
    z-index: -1;
    left: 0;
    top: 0;
    width: 100%;
    height: 100%;
    background: url(${backgroundImage}) center center no-repeat;
    background-size: cover;
    filter: brightness(0.2) blur(4px);
    box-shadow: 0px 0px 1px black;
  }

  & h3 {
    margin: 0;
    font-size: 2em;
    text-align: center;
  }

  & h4 {
    margin: 0;
    font-size: 1em;
    font-weight: 400;
    text-align: center;
  }
`

const Form = styled.form`
  display: flex;
  flex-direction: column;
  align-items: center;
  row-gap: 1em;
  width: 100%;
`

const InputGroup = styled.div`
  display: flex;
  flex-direction: column;
  width: 40%;
  min-width: 20em;
  max-width: 30em;

  & input, textarea {
    padding: 0.5em;
    font-family: Rubik;
    border-radius: 4px;
    box-shadow: 2px 2px 1px black;
    border: 0;
    font-size: 1em;
  }
`

const SubmitButton = styled.button`
  background: white;
  border: 0;
  color: black;
  padding: 1em 3em;
  border-radius: 4px;
  font-size: 1em;

  &:hover {
    box-shadow: 3px 3px 2px lightblue;
  }
`

export default ContactForm
